/// Extract content from a byte array.
///
/// This is the main entry point for in-memory extraction. It performs the following steps:
/// 1. Validate MIME type
/// 2. Handle legacy format conversion if needed
/// 3. Select appropriate extractor from registry
/// 4. Extract content
/// 5. Run post-processing pipeline
///
/// **Returns:**
///
/// An `ExtractionResult` containing the extracted content and metadata.
///
/// **Errors:**
///
/// Returns `KreuzbergError.Validation` if MIME type is invalid.
/// Returns `KreuzbergError.UnsupportedFormat` if MIME type is not supported.
pub async fn extract_bytes(
    content: Vec<u8>,
    mime_type: String,
    config: kreuzberg::ExtractionConfig,
) -> Result<kreuzberg::ExtractionResult, String> {
    kreuzberg::extract_bytes(&content, &mime_type, &config)
        .await
        .map(|v| v)
        .map_err(|e| e.to_string())
}

/// Extract content from a file.
///
/// This is the main entry point for file-based extraction. It performs the following steps:
/// 1. Check cache for existing result (if caching enabled)
/// 2. Detect or validate MIME type
/// 3. Select appropriate extractor from registry
/// 4. Extract content
/// 5. Run post-processing pipeline
/// 6. Store result in cache (if caching enabled)
///
/// **Returns:**
///
/// An `ExtractionResult` containing the extracted content and metadata.
///
/// **Errors:**
///
/// Returns `KreuzbergError.Io` if the file doesn't exist (NotFound) or for other file I/O errors.
/// Returns `KreuzbergError.UnsupportedFormat` if MIME type is not supported.
pub async fn extract_file(
    path: String,
    mime_type: Option<String>,
    config: kreuzberg::ExtractionConfig,
) -> Result<kreuzberg::ExtractionResult, String> {
    kreuzberg::extract_file(std::path::PathBuf::from(path), mime_type.as_deref(), &config)
        .await
        .map(|v| v)
        .map_err(|e| e.to_string())
}

/// Synchronous wrapper for `extract_file`.
///
/// This is a convenience function that blocks the current thread until extraction completes.
/// For async code, use `extract_file` directly.
///
/// Uses the global Tokio runtime for 100x+ performance improvement over creating
/// a new runtime per call. Always uses the global runtime to avoid nested runtime issues.
///
/// This function is only available with the `tokio-runtime` feature. For WASM targets,
/// use a truly synchronous extraction approach instead.
pub fn extract_file_sync(
    path: String,
    mime_type: Option<String>,
    config: kreuzberg::ExtractionConfig,
) -> Result<kreuzberg::ExtractionResult, String> {
    kreuzberg::extract_file_sync(std::path::PathBuf::from(path), mime_type.as_deref(), &config)
        .map(|v| v)
        .map_err(|e| e.to_string())
}

/// Synchronous wrapper for `extract_bytes`.
///
/// Uses the global Tokio runtime for 100x+ performance improvement over creating
/// a new runtime per call.
///
/// With the `tokio-runtime` feature, this blocks the current thread using the global
/// Tokio runtime. Without it (WASM), this calls a truly synchronous implementation.
pub fn extract_bytes_sync(
    content: Vec<u8>,
    mime_type: String,
    config: kreuzberg::ExtractionConfig,
) -> Result<kreuzberg::ExtractionResult, String> {
    kreuzberg::extract_bytes_sync(&content, &mime_type, &config)
        .map(|v| v)
        .map_err(|e| e.to_string())
}

/// Synchronous wrapper for `batch_extract_file`.
///
/// Uses the global Tokio runtime for optimal performance.
/// Only available with `tokio-runtime` (WASM has no filesystem).
pub fn batch_extract_file_sync(
    items: Vec<String>,
    config: kreuzberg::ExtractionConfig,
) -> Result<Vec<kreuzberg::ExtractionResult>, String> {
    kreuzberg::batch_extract_file_sync(
        items
            .into_iter()
            .map(|p| (std::path::PathBuf::from(p), None))
            .collect::<Vec<_>>(),
        &config,
    )
    .map(|v| v)
    .map_err(|e| e.to_string())
}

/// Extract content from multiple files concurrently.
///
/// This function processes multiple files in parallel, automatically managing
/// concurrency to prevent resource exhaustion. The concurrency limit can be
/// configured via `ExtractionConfig.max_concurrent_extractions` or defaults
/// to `(num_cpus * 1.5).ceil()`.
///
/// Each file can optionally specify a `FileExtractionConfig` that overrides specific
/// fields from the batch-level `config`. Pass `null` for a file to use the batch defaults.
/// Batch-level settings like `max_concurrent_extractions` and `use_cache` are always
/// taken from the batch-level `config`.
///
///   config to use the batch-level defaults for that file.
/// * `config` - Batch-level extraction configuration (provides defaults and batch settings)
///
/// **Returns:**
///
/// A vector of `ExtractionResult` in the same order as the input items.
///
/// **Errors:**
///
/// Individual file errors are captured in the result metadata. System errors
/// (IO, RuntimeError equivalents) will bubble up and fail the entire batch.
///
/// Simple usage with no per-file overrides:
///
///
/// Per-file configuration overrides:
pub async fn batch_extract_file(
    items: Vec<String>,
    config: kreuzberg::ExtractionConfig,
) -> Result<Vec<kreuzberg::ExtractionResult>, String> {
    kreuzberg::batch_extract_file(
        items
            .into_iter()
            .map(|p| (std::path::PathBuf::from(p), None))
            .collect::<Vec<_>>(),
        &config,
    )
    .await
    .map(|v| v)
    .map_err(|e| e.to_string())
}

